#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M;
        scanf("%d", &M);
        int *base = (int*)malloc(M * sizeof(int));
        int *power = (int*)malloc(M * sizeof(int));
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &base[i], &power[i]);
        }
        qsort(base, M, sizeof(int), compare);
        long long *dp = (long long*)malloc((1 << M) * sizeof(long long));
        dp[0] = 1;
        for (int mask = 1; mask < (1 << M); mask++) {
            int i = __builtin_ctz(mask);
            dp[mask] = dp[mask ^ (1 << i)];
            for (int j = i + 1; j < M; j++) {
                if ((mask >> j) & 1) {
                    if (base[j] % base[i] == 0) {
                        dp[mask] = (dp[mask] + dp[mask ^ (1 << j)]) % MOD;
                    }
                }
            }
        }
        int max_size = 0;
        long long max_count = 0;
        for (int mask = 0; mask < (1 << M); mask++) {
            int size = __builtin_popcount(mask);
            if (size > max_size) {
                max_size = size;
                max_count = dp[mask];
            } else if (size == max_size) {
                max_count = (max_count + dp[mask]) % MOD;
            }
        }
        printf("%d %lld\n", max_size, max_count);
        free(base);
        free(power);
        free(dp);
    }
    return 0;
}

